import { Component, OnInit } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { Router, ActivatedRoute } from '@angular/router';
import { AuthService } from '../../../core/services/auth.service';
import { LoggerService } from '../../../core/services/logger.service';

/**
 * LoginComponent - Smart component for user authentication
 */
@Component({
  selector: 'app-login',
  templateUrl: './login.component.html',
  styleUrls: ['./login.component.scss'],
})
export class LoginComponent implements OnInit {
  loginForm: FormGroup;
  loading = false;
  submitted = false;
  returnUrl: string = '';
  error = '';

  constructor(
    private formBuilder: FormBuilder,
    private route: ActivatedRoute,
    private router: Router,
    private authService: AuthService,
    private logger: LoggerService,
  ) {
    this.loginForm = this.formBuilder.group({
      email: ['', [Validators.required, Validators.email]],
      password: ['', [Validators.required, Validators.minLength(6)]],
    });
  }

  ngOnInit(): void {
    // Get return url from route parameters or default to '/'
    this.returnUrl = this.route.snapshot.queryParams['returnUrl'] || '/';
  }

  get form() {
    return this.loginForm.controls;
  }

  onSubmit(): void {
    this.submitted = true;

    // Stop if form is invalid
    if (this.loginForm.invalid) {
      return;
    }

    this.loading = true;
    this.error = '';

    this.authService
      .login(this.loginForm.value.email, this.loginForm.value.password)
      .subscribe({
        next: () => {
          this.logger.log('Login successful, redirecting...');
          this.router.navigateByUrl(this.returnUrl);
        },
        error: (error) => {
          this.loading = false;
          this.error = error?.message || 'Login failed';
          this.logger.error('Login failed', undefined, { error });
        },
      });
  }
}
<div class="login-container">
  <div class="login-card">
    <h1>TallerNova - Login</h1>
    
    <form [formGroup]="loginForm" (ngSubmit)="onSubmit()">
      <div class="form-group">
        <label for="email">Email</label>
        <input
          type="email"
          id="email"
          class="form-control"
          formControlName="email"
          [class.is-invalid]="submitted && form['email'].errors"
          placeholder="Enter your email"
        />
        <div class="invalid-feedback" *ngIf="submitted && form['email'].errors">
          <span *ngIf="form['email'].hasError('required')">Email is required</span>
          <span *ngIf="form['email'].hasError('email')">Please enter a valid email</span>
        </div>
      </div>

      <div class="form-group">
        <label for="password">Password</label>
        <input
          type="password"
          id="password"
          class="form-control"
          formControlName="password"
          [class.is-invalid]="submitted && form['password'].errors"
          placeholder="Enter your password"
        />
        <div class="invalid-feedback" *ngIf="submitted && form['password'].errors">
          <span *ngIf="form['password'].hasError('required')">Password is required</span>
          <span *ngIf="form['password'].hasError('minlength')">Password must be at least 6 characters</span>
        </div>
      </div>

      <div *ngIf="error" class="alert alert-danger">
        {{ error }}
      </div>

      <button
        type="submit"
        class="btn btn-primary w-100"
        [disabled]="loading"
      >
        <span *ngIf="loading" class="spinner"></span>
        {{ loading ? 'Logging in...' : 'Login' }}
      </button>
    </form>

    <div class="test-credentials">
      <p><strong>Test Credentials:</strong></p>
      <p>Admin: admin&#64;test.com / password123</p>
      <p>Viewer: viewer&#64;test.com / password123</p>
    </div>
  </div>
</div>
